/**
 * Creates a read-only signal whose value is derived from a single source signal.
 *
 * @param source - The source signal to derive from.
 * @param fn - A function that receives the source value and returns the derived value.
 * @returns A `ComputedSignal` that updates whenever the source changes.
 *
 * @example
 * const count = new SSignal(5);
 * const doubled = computed(count, (n) => n * 2);
 * doubled.subscribe((v) => console.log(v)); // logs: 10
 * count.value = 10; // logs: 20
 */
export declare function computed<T, R>(source: SSignal<T>, fn: (value: T) => R): ComputedSignal<R>;

/**
 * Creates a read-only signal whose value is derived from multiple source signals.
 *
 * @param sources - Tuple of source signals to derive from.
 * @param fn - A function that receives the current values of all sources as a tuple.
 * @returns A `ComputedSignal` that updates whenever any source changes.
 *
 * @example
 * const price = new SSignal(100);
 * const qty   = new SSignal(3);
 * const total = computed([price, qty], ([p, q]) => p * q);
 * total.subscribe((v) => console.log(v)); // logs: 300
 * price.value = 200; // logs: 600
 */
export declare function computed<Sources extends readonly SSignal<any>[], R>(sources: [...Sources], fn: (values: ExtractValues<Sources>) => R): ComputedSignal<R>;

/**
 * A read-only signal whose value is automatically derived from one or more source signals.
 * Use `computed()` to create instances — do not instantiate directly.
 *
 * Call `dispose()` when the computed signal is no longer needed to remove all source subscriptions.
 */
export declare class ComputedSignal<T> extends SSignal<T> {
    #private;
    /* Excluded from this release type: __constructor */
    get value(): T;
    /**
     * @throws {TypeError} Always — computed signals are read-only.
     */
    set value(_: never);
    /**
     * Removes all subscriptions to source signals.
     * Call this when the computed signal is no longer needed to free memory.
     */
    dispose(): void;
}

declare type ExtractValues<T extends readonly SSignal<any>[]> = {
    [K in keyof T]: T[K] extends SSignal<infer V> ? V : never;
};

/**
 * A reactive signal that extends EventTarget to provide observable state management.
 * Supports any value type, including reactive Map and Set instances that emit change
 * events on mutation.
 *
 * @template T - The type of the value held by the signal.
 *
 * @example
 * const count = new SSignal(0);
 * count.subscribe((value) => console.log(value));
 * count.value = 1;        // logs: 1
 * count.value = (n) => n + 1; // logs: 2
 */
declare class SSignal<T = unknown> extends EventTarget {
    #private;
    /**
     * Creates a new SSignal instance.
     * If the initial value is a Map or Set, it is wrapped in a reactive proxy that
     * dispatches change events on mutating calls.
     *
     * @param value - The initial value of the signal.
     */
    constructor(value: T);
    /**
     * Returns the current value of the signal.
     */
    get value(): T;
    /**
     * Sets a new value for the signal. Accepts either a direct value or an updater
     * function that receives the previous value and returns the next one.
     * No event is dispatched when the new value is strictly equal to the current one.
     *
     * @param newValue - The next value, or a function `(prev: T) => T`.
     */
    set value(newValue: T | ((prev: T) => T));
    /**
     * Registers a callback that is invoked whenever the signal value changes.
     * Returns an unsubscribe function that removes the listener when called.
     *
     * Optionally accepts an AbortSignal to cancel the subscription automatically.
     * If the signal is already aborted at call time, the callback is never registered.
     *
     * @param callback - Function called with the new value on each change.
     * @param options.signal - Optional AbortSignal to cancel the subscription.
     * @param options.immediate - If true, fires the callback synchronously with the current value before returning.
     * @returns A function that removes the subscription when called.
     *
     * @example
     * const controller = new AbortController();
     * signal.subscribe((v) => console.log(v), { signal: controller.signal });
     * controller.abort(); // unsubscribes
     *
     * @example
     * signal.subscribe((v) => render(v), { immediate: true }); // render called immediately with current value
     */
    subscribe(callback: (value: T) => void, options?: {
        signal?: AbortSignal;
        immediate?: boolean;
    }): () => void;
    /**
     * Registers a callback that is invoked only on the next signal value change.
     * Returns an unsubscribe function that can cancel the pending callback before
     * it fires.
     *
     * Optionally accepts an AbortSignal to cancel the one-time subscription
     * automatically. If the signal is already aborted at call time, the callback is
     * never registered.
     *
     * @param callback - Function called with the new value on the next change.
     * @param options.signal - Optional AbortSignal to cancel the subscription.
     * @returns A function that removes the pending one-time subscription.
     *
     * @example
     * const unsubscribe = signal.once((v) => console.log('first change:', v));
     * unsubscribe(); // cancels if the signal has not changed yet
     */
    once(callback: (value: T) => void, options?: {
        signal?: AbortSignal;
    }): () => void;
}
export default SSignal;

